html:
{# Work Order Contract — V2 print format.
   Polished, contract-grade typography. Single navy accent. Designed
   for A4 portrait. Sections:
     Page 1: Title block + parties + scope + schedule + summary + amount in words
     Page 2: Terms & Conditions + General Conditions + Signatures
     Page 3+: Annexure 1 — Detailed BOQ + Deviation Limits #}

<style>
  /* ----- Print-targeted scope ----- */
  .wo-print, .wo-print * { box-sizing: border-box; }
  .wo-print {
    font-family: "Helvetica Neue", "Segoe UI", "Inter", Arial, sans-serif;
    color: #111;
    font-size: 9.5pt;
    line-height: 1.5;
    font-variant-numeric: tabular-nums;
    -webkit-font-feature-settings: "tnum";
    font-feature-settings: "tnum";
  }
  .wo-print p { margin: 0 0 6px; }
  .wo-print a { color: inherit; text-decoration: none; }

  /* ----- Typographic system ----- */
  .wo-print .display-title {
    font-family: "Georgia", "Times New Roman", "Cambria", serif;
    font-size: 28pt;
    font-weight: 700;
    letter-spacing: 4pt;
    text-align: center;
    color: #1a2942;
    margin: 0;
    line-height: 1.1;
  }
  .wo-print .display-sub {
    font-size: 9pt;
    letter-spacing: 3pt;
    text-transform: uppercase;
    text-align: center;
    color: #666;
    margin: 4px 0 0;
  }
  .wo-print .section-label {
    font-size: 8.5pt;
    letter-spacing: 2.5pt;
    text-transform: uppercase;
    color: #1a2942;
    font-weight: 600;
    margin: 22px 0 8px;
    padding-bottom: 4px;
    border-bottom: 1px solid #1a2942;
  }
  .wo-print .sub-label {
    font-size: 9pt;
    font-weight: 700;
    color: #1a2942;
    margin: 14px 0 6px;
    letter-spacing: 0.5pt;
  }
  .wo-print .muted { color: #777; font-size: 8.5pt; }

  /* ----- Cover/title block ----- */
  .wo-print .cover-block {
    border-top: 3px solid #1a2942;
    border-bottom: 1px solid #1a2942;
    padding: 18px 0 16px;
    margin-bottom: 22px;
  }
  .wo-print .cover-meta {
    margin-top: 14px;
    display: table;
    width: 100%;
    border-collapse: collapse;
  }
  .wo-print .cover-meta > div {
    display: table-cell;
    padding: 0 6px;
    vertical-align: top;
    width: 33.33%;
    text-align: center;
  }
  .wo-print .meta-label {
    font-size: 7.5pt;
    letter-spacing: 1.5pt;
    text-transform: uppercase;
    color: #888;
    margin-bottom: 2px;
  }
  .wo-print .meta-value {
    font-size: 11pt;
    font-weight: 600;
    color: #1a2942;
    letter-spacing: 0.3pt;
  }
  .wo-print .status-pill {
    display: inline-block;
    padding: 1px 8px;
    font-size: 7.5pt;
    letter-spacing: 1.5pt;
    text-transform: uppercase;
    font-weight: 600;
    border: 1px solid #1a2942;
    color: #1a2942;
    border-radius: 2px;
  }
  .wo-print .status-pill.cancelled { color: #a91414; border-color: #a91414; }
  .wo-print .status-pill.draft    { color: #b75c00; border-color: #b75c00; }
  .wo-print .status-pill.amended  { color: #154a98; border-color: #154a98; }

  /* ----- Parties block ----- */
  .wo-print .parties {
    width: 100%;
    border-collapse: collapse;
    margin: 0 0 8px;
  }
  .wo-print .parties td {
    width: 50%;
    padding: 12px 16px 12px 0;
    vertical-align: top;
  }
  .wo-print .parties td + td { padding-left: 16px; border-left: 1px solid #ddd; }
  .wo-print .party-role {
    font-size: 7.5pt;
    letter-spacing: 2pt;
    text-transform: uppercase;
    color: #888;
    margin-bottom: 3px;
  }
  .wo-print .party-name {
    font-size: 11pt;
    font-weight: 700;
    color: #111;
    margin-bottom: 4px;
    line-height: 1.3;
  }
  .wo-print .party-address {
    font-size: 9pt;
    color: #333;
    line-height: 1.4;
  }
  .wo-print .party-gst {
    font-size: 8.5pt;
    color: #666;
    margin-top: 3px;
    letter-spacing: 0.3pt;
  }

  /* ----- Scope block ----- */
  .wo-print .scope-title {
    font-size: 12pt;
    font-weight: 700;
    color: #111;
    margin: 0 0 4px;
    line-height: 1.3;
  }
  .wo-print .scope-meta {
    font-size: 9pt;
    color: #555;
    margin-bottom: 8px;
  }
  .wo-print .scope-body {
    font-size: 9.5pt;
    color: #222;
    line-height: 1.55;
    text-align: justify;
  }
  .wo-print .scope-body p { margin: 4px 0; }

  /* ----- Schedule strip ----- */
  .wo-print .schedule {
    display: table;
    width: 100%;
    border: 1px solid #ddd;
    background: #fafafa;
    border-collapse: separate;
    margin-top: 8px;
  }
  .wo-print .schedule > div {
    display: table-cell;
    padding: 10px 14px;
    width: 50%;
    vertical-align: middle;
  }
  .wo-print .schedule > div + div { border-left: 1px solid #ddd; }
  .wo-print .sched-label {
    font-size: 7.5pt;
    letter-spacing: 1.5pt;
    text-transform: uppercase;
    color: #888;
  }
  .wo-print .sched-value {
    font-size: 11pt;
    font-weight: 600;
    color: #1a2942;
    margin-top: 2px;
  }

  /* ----- Summary table ----- */
  .wo-print .summary-table {
    width: 100%;
    border-collapse: collapse;
    margin: 6px 0 8px;
  }
  .wo-print .summary-table th,
  .wo-print .summary-table td {
    padding: 8px 10px;
    border-bottom: 1px solid #e6e6e6;
    text-align: left;
    font-size: 10pt;
  }
  .wo-print .summary-table th {
    font-size: 7.5pt;
    letter-spacing: 1.5pt;
    text-transform: uppercase;
    color: #888;
    font-weight: 600;
    border-bottom: 1.5px solid #1a2942;
    padding-top: 6px;
    padding-bottom: 6px;
  }
  .wo-print .summary-table td.head { font-weight: 600; color: #111; }
  .wo-print .summary-table td.amt,
  .wo-print .summary-table th.amt { text-align: right; white-space: nowrap; }
  .wo-print .summary-table .total-row td {
    border-top: 1.5px solid #1a2942;
    border-bottom: none;
    font-weight: 700;
    color: #1a2942;
    font-size: 11pt;
    padding-top: 10px;
  }

  /* ----- Amount-in-words ----- */
  .wo-print .amount-in-words {
    background: #faf8f3;
    border-left: 3px solid #c9a25a;
    padding: 10px 14px;
    margin: 10px 0 6px;
    font-style: italic;
    color: #4d3a14;
    font-size: 9.5pt;
  }

  /* ----- Note callout ----- */
  .wo-print .annexure-note {
    font-size: 8.5pt;
    color: #555;
    margin: 10px 0;
    padding-top: 10px;
    border-top: 1px dashed #ccc;
    text-align: center;
    letter-spacing: 0.3pt;
  }

  /* ----- Terms grid (flex-based to avoid Bootstrap .label/.value collision) ----- */
  .wo-print .terms-grid {
    display: flex;
    flex-wrap: wrap;
    margin: 4px 0 14px;
    border-top: 1px solid #ececec;
  }
  .wo-print .terms-row {
    width: 50%;
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    padding: 9px 14px 9px 0;
    border-bottom: 1px solid #ececec;
    box-sizing: border-box;
  }
  .wo-print .terms-row + .terms-row { /* right column extra padding */ }
  .wo-print .terms-row:nth-child(even) { padding-left: 14px; padding-right: 0; }
  .wo-print .term-k {
    color: #555;
    font-size: 9pt;
    font-weight: 500;
    line-height: 1.3;
    flex: 1;
  }
  .wo-print .term-v {
    color: #111;
    font-weight: 700;
    font-size: 10pt;
    text-align: right;
    white-space: nowrap;
    margin-left: 10px;
  }
  .wo-print .terms-row.full { width: 100%; padding-right: 0; }

  /* ----- General conditions ----- */
  .wo-print .conditions {
    font-size: 9pt;
    line-height: 1.55;
    color: #222;
    padding-left: 18px;
    margin: 4px 0;
  }
  .wo-print .conditions li { margin: 4px 0; padding-left: 4px; }

  /* ----- Signature block ----- */
  .wo-print .signature-block {
    margin-top: 32px;
    page-break-inside: avoid;
  }
  .wo-print .sig-grid {
    width: 100%;
    border-collapse: separate;
    border-spacing: 24px 0;
    margin-top: 6px;
  }
  .wo-print .sig-grid td {
    width: 50%;
    padding: 0;
    vertical-align: top;
  }
  .wo-print .sig-role {
    font-size: 7.5pt;
    letter-spacing: 2pt;
    text-transform: uppercase;
    color: #888;
    margin-bottom: 4px;
  }
  .wo-print .sig-name {
    font-size: 10pt;
    font-weight: 700;
    color: #111;
    line-height: 1.35;
    /* Reserve fixed vertical space so signature lines stay aligned across
       both columns regardless of how the party name wraps. ~3 lines worth
       of height ensures even a long 2-line company name lands above a
       consistent signature baseline. */
    min-height: 42px;
    margin-bottom: 30px;
    display: flex;
    align-items: flex-start;
  }
  .wo-print .sig-line {
    border-top: 1px solid #333;
    margin-bottom: 4px;
  }
  .wo-print .sig-caption {
    font-size: 8.5pt;
    color: #555;
    font-weight: 600;
    margin-bottom: 6px;
  }
  .wo-print .sig-detail {
    font-size: 8.5pt;
    color: #777;
    line-height: 1.7;
  }
  .wo-print .sig-detail span { display: inline-block; min-width: 60pt; border-bottom: 1px dotted #999; padding: 0 6px; }

  /* ----- Footnote ----- */
  .wo-print .doc-footnote {
    margin-top: 22px;
    padding-top: 8px;
    border-top: 1px solid #e8e8e8;
    font-size: 8pt;
    color: #888;
    text-align: center;
    line-height: 1.4;
  }

  /* ----- Annexure cover ----- */
  .wo-print .annexure-cover { text-align: center; padding: 30pt 0 22pt; }
  .wo-print .annexure-overline {
    font-size: 8pt;
    letter-spacing: 4pt;
    text-transform: uppercase;
    color: #888;
    margin-bottom: 4px;
  }
  .wo-print .annexure-title {
    font-family: "Georgia", "Times New Roman", "Cambria", serif;
    font-size: 22pt;
    font-weight: 700;
    color: #1a2942;
    letter-spacing: 2pt;
    margin: 0;
  }
  .wo-print .annexure-rule {
    width: 80pt;
    border-top: 2px solid #c9a25a;
    margin: 12px auto 14px;
  }
  .wo-print .annexure-ref {
    font-size: 9pt;
    color: #555;
    margin: 0;
    letter-spacing: 0.3pt;
  }

  /* ----- BOQ table ----- */
  .wo-print .boq-table {
    width: 100%;
    border-collapse: collapse;
    margin: 0 0 12px;
    font-size: 9pt;
  }
  .wo-print .boq-table th, .wo-print .boq-table td {
    padding: 5px 5px;
    border-bottom: 1px solid #e6e6e6;
    vertical-align: top;
  }
  .wo-print .boq-table thead th {
    background: #1a2942;
    color: #fff;
    text-align: left;
    font-size: 7.5pt;
    letter-spacing: 0.8pt;
    text-transform: uppercase;
    font-weight: 600;
    padding: 6px 5px;
  }
  .wo-print .boq-table th.amt, .wo-print .boq-table td.amt { text-align: right; white-space: nowrap; }
  .wo-print .boq-table .head-row td {
    background: #f5f1e6;
    color: #1a2942;
    font-weight: 700;
    font-size: 9pt;
    letter-spacing: 0.5pt;
    padding: 7px 8px;
    border-bottom: 1px solid #c9a25a;
  }
  .wo-print .boq-table .subtotal td {
    background: #fbfaf7;
    font-weight: 700;
    color: #1a2942;
    font-size: 9pt;
    padding: 7px 8px;
    border-top: 1px solid #c9a25a;
    border-bottom: 1px solid #c9a25a;
  }
  .wo-print .boq-table tfoot td {
    background: #1a2942;
    color: #fff;
    font-weight: 700;
    font-size: 10.5pt;
    padding: 10px 8px;
    letter-spacing: 0.5pt;
    border-bottom: none;
  }
  .wo-print .boq-desc { font-size: 8.5pt; color: #333; line-height: 1.4; }
  .wo-print .boq-desc .item-num { color: #888; font-size: 8pt; margin-right: 4px; }

  /* ----- Deviation table ----- */
  .wo-print .deviation-table {
    width: 100%;
    border-collapse: collapse;
    margin: 4px 0;
    font-size: 9pt;
  }
  .wo-print .deviation-table th, .wo-print .deviation-table td {
    padding: 6px 8px;
    border-bottom: 1px solid #e6e6e6;
    vertical-align: top;
  }
  .wo-print .deviation-table thead th {
    background: #f5f5f3;
    text-align: left;
    font-size: 7.5pt;
    letter-spacing: 1.2pt;
    text-transform: uppercase;
    color: #555;
    font-weight: 600;
    border-bottom: 1px solid #999;
  }
  .wo-print .deviation-table th.amt, .wo-print .deviation-table td.amt { text-align: right; white-space: nowrap; }
  .wo-print .deviation-table .dev-strict td.dev { color: #a91414; font-weight: 700; }

  /* ----- Page break controls ----- */
  .wo-print .page-break { page-break-after: always; break-after: page; }
  .wo-print .no-break  { page-break-inside: avoid; }
  .wo-print table     { page-break-inside: auto; }
  .wo-print thead     { display: table-header-group; }
  .wo-print tfoot     { display: table-footer-group; }
  .wo-print tr        { page-break-inside: avoid; }
  .wo-print h1, .wo-print h2, .wo-print h3, .wo-print .section-label { page-break-after: avoid; }
</style>

{# ===================== Helpers ===================== #}
{%- set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "INR" -%}
{%- macro money(amt) -%}{{ frappe.utils.fmt_money(amt or 0, currency=company_currency) }}{%- endmacro -%}
{%- macro show_date(d) -%}{%- if d -%}{{ frappe.utils.formatdate(d, "dd MMM yyyy") }}{%- else -%}—{%- endif -%}{%- endmacro -%}
{%- macro show_pct(v) -%}{%- if v is none -%}—{%- else -%}{{ "%.2f"|format(v|float) }}%{%- endif -%}{%- endmacro -%}
{%- macro qty(v, uom) -%}{{ "{:,.3f}".format(v|float if v is not none else 0) }}{% if uom %} <span class="muted">{{ uom }}</span>{% endif %}{%- endmacro -%}

<div class="wo-print">

{# ================================================== #}
{# COVER BLOCK                                         #}
{# ================================================== #}

<div class="cover-block">
  <h1 class="display-title">WORK ORDER</h1>
  <p class="display-sub">Construction &amp; Maintenance Services Contract</p>
  <div class="cover-meta">
    <div>
      <div class="meta-label">Document No.</div>
      <div class="meta-value">{{ doc.name }}</div>
    </div>
    <div>
      <div class="meta-label">Issued On</div>
      <div class="meta-value">{{ show_date(doc.wo_date) }}</div>
    </div>
    <div>
      <div class="meta-label">Status</div>
      <div class="meta-value">
        {%- if doc.amended_from -%}
          <span class="status-pill amended">Amended</span>
          <div class="muted" style="font-size: 7.5pt; margin-top: 2px;">supersedes {{ doc.amended_from }}</div>
        {%- elif doc.docstatus == 0 -%}
          <span class="status-pill draft">Draft</span>
        {%- elif doc.docstatus == 1 -%}
          <span class="status-pill">Active</span>
        {%- elif doc.docstatus == 2 -%}
          <span class="status-pill cancelled">Cancelled</span>
        {%- endif -%}
      </div>
    </div>
  </div>
</div>

{# ================================================== #}
{# PARTIES                                             #}
{# ================================================== #}

<table class="parties">
  <tr>
    <td>
      <div class="party-role">Employer</div>
      <div class="party-name">{{ doc.company }}</div>
      {%- set caddr = frappe.db.get_value("Address",
            {"link_doctype": "Company", "link_name": doc.company, "is_primary_address": 1},
            ["address_line1", "address_line2", "city", "state", "pincode", "country", "gstin"],
            as_dict=True) -%}
      {%- if caddr -%}
        <div class="party-address">
          {{ caddr.address_line1 or "" }}{% if caddr.address_line2 %}, {{ caddr.address_line2 }}{% endif %}<br>
          {{ caddr.city or "" }}{% if caddr.state %}, {{ caddr.state }}{% endif %}{% if caddr.pincode %} – {{ caddr.pincode }}{% endif %}{% if caddr.country %}<br>{{ caddr.country }}{% endif %}
        </div>
        {%- if caddr.gstin -%}<div class="party-gst">GSTIN <strong>{{ caddr.gstin }}</strong></div>{%- endif -%}
      {%- endif -%}
    </td>
    <td>
      <div class="party-role">Contractor</div>
      <div class="party-name">{{ doc.supplier_name or doc.supplier }}</div>
      {%- set saddr = frappe.db.get_value("Address",
            {"link_doctype": "Supplier", "link_name": doc.supplier, "is_primary_address": 1},
            ["address_line1", "address_line2", "city", "state", "pincode", "gstin"],
            as_dict=True) -%}
      {%- if saddr -%}
        <div class="party-address">
          {{ saddr.address_line1 or "" }}{% if saddr.address_line2 %}, {{ saddr.address_line2 }}{% endif %}<br>
          {{ saddr.city or "" }}{% if saddr.state %}, {{ saddr.state }}{% endif %}{% if saddr.pincode %} – {{ saddr.pincode }}{% endif %}
        </div>
        {%- if saddr.gstin -%}<div class="party-gst">GSTIN <strong>{{ saddr.gstin }}</strong></div>{%- endif -%}
      {%- endif -%}
      {%- set sup_pan = frappe.db.get_value("Supplier", doc.supplier, "tax_id") -%}
      {%- if sup_pan and not (saddr and saddr.gstin) -%}<div class="party-gst">PAN <strong>{{ sup_pan }}</strong></div>{%- endif -%}
    </td>
  </tr>
</table>

{# ================================================== #}
{# SCOPE                                               #}
{# ================================================== #}

<div class="section-label">Scope of Work</div>
<div class="scope-title">{{ doc.work_title }}</div>
{% if doc.site_location %}
<div class="scope-meta"><strong>Site:</strong> {{ doc.site_location }}</div>
{% endif %}
{% if doc.project %}
<div class="scope-meta"><strong>Project:</strong> {{ doc.project }}</div>
{% endif %}
{% if doc.work_description %}
<div class="scope-body">{{ doc.work_description }}</div>
{% endif %}

{# ================================================== #}
{# SCHEDULE                                            #}
{# ================================================== #}

{% if doc.scheduled_start_date or doc.scheduled_completion_date %}
<div class="section-label">Schedule</div>
<div class="schedule">
  <div>
    <div class="sched-label">Scheduled Start</div>
    <div class="sched-value">{{ show_date(doc.scheduled_start_date) }}</div>
  </div>
  <div>
    <div class="sched-label">Scheduled Completion</div>
    <div class="sched-value">{{ show_date(doc.scheduled_completion_date) }}</div>
  </div>
</div>
{% endif %}

{# ================================================== #}
{# SUMMARY OF WORK HEADS                               #}
{# ================================================== #}

<div class="section-label">Summary of Work Heads</div>
<table class="summary-table">
  <thead>
    <tr>
      <th style="width: 4%;">#</th>
      <th>Work Head</th>
      <th class="amt" style="width: 19%;">Amount (excl. tax)</th>
      <th class="amt" style="width: 19%;">Amount (incl. tax)</th>
    </tr>
  </thead>
  <tbody>
    {% for s in doc.summary_items %}
    <tr>
      <td class="muted">{{ "%02d"|format(loop.index) }}</td>
      <td class="head">{{ s.summary_head }}</td>
      <td class="amt">{{ money(s.amount) }}</td>
      <td class="amt">{{ money(s.amount_with_tax) }}</td>
    </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr class="total-row">
      <td colspan="2">Total Contract Value</td>
      <td class="amt">{{ money(doc.total_amount) }}</td>
      <td class="amt">{{ money(doc.total_amount_with_tax) }}</td>
    </tr>
  </tfoot>
</table>

<div class="amount-in-words">
  In words (incl. tax): {{ frappe.utils.money_in_words(doc.total_amount_with_tax or 0, company_currency) }}
</div>

<div class="annexure-note">
  Detailed Bill of Quantities — see <strong>Annexure 1</strong>. It forms an integral part of this contract.
</div>

<div class="page-break"></div>

{# ================================================== #}
{# PAGE 2 — TERMS & SIGNATURES                         #}
{# ================================================== #}

<div class="section-label">Financial Terms</div>
<div class="terms-grid">
  <div class="terms-row">
    <span class="term-k">Retention per RA Bill</span>
    <span class="term-v">{{ show_pct(doc.retention_percentage) }}</span>
  </div>
  <div class="terms-row">
    <span class="term-k">Defect Liability Period</span>
    <span class="term-v">{{ doc.dlp_months or 0 }} months</span>
  </div>
  <div class="terms-row">
    <span class="term-k">Mobilization Advance</span>
    <span class="term-v">{{ show_pct(doc.mobilization_advance_pct) }}</span>
  </div>
  <div class="terms-row">
    <span class="term-k">Mobilization Recovery per RA</span>
    <span class="term-v">{{ show_pct(doc.mobilization_recovery_pct) }}</span>
  </div>
  <div class="terms-row">
    <span class="term-k">Material Advance</span>
    <span class="term-v">{{ show_pct(doc.material_advance_pct) }}</span>
  </div>
  <div class="terms-row">
    <span class="term-k">Material Recovery per RA</span>
    <span class="term-v">{{ show_pct(doc.material_recovery_pct) }}</span>
  </div>
</div>

<div class="sub-label">Retention Release Schedule</div>
<div class="terms-grid">
  <div class="terms-row">
    <span class="term-k">Release on Final Bill</span>
